import React, { useState, useEffect, useRef } from 'react';
import './Showreel.css';

export default function Showreel() {
  const [sec, setSec] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    const id = setInterval(() => setSec(s => (s + 1) % 167), 1000);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) ref.current.querySelectorAll('.reveal').forEach(r => r.classList.add('visible'));
    }, { threshold: 0.1 });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  const m = Math.floor(sec / 60), s = sec % 60;
  const pct = (sec / 167) * 100;
  const time = `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')} / 02:47`;

  return (
    <section className="section" id="reel" ref={ref} style={{ background: 'var(--panel)' }}>
      <p className="sec-tag reveal">04 — Showreel</p>
      <h2 className="sec-title reveal">The Reel</h2>

      <div className="player-wrap reveal">
        <div className="player-screen">
          <div className="player-bg-text">SHOWREEL 2025</div>
          <div className="player-center">
            <button className="player-play-btn">
              <svg width="22" height="22" viewBox="0 0 22 22" fill="currentColor">
                <polygon points="5,2 20,11 5,20" />
              </svg>
            </button>
            <span className="player-label">SAKSHAM MANCHANDA · REEL 2025</span>
          </div>
        </div>
        <div className="player-controls">
          <button className="pc-btn">
            <svg width="14" height="14" viewBox="0 0 14 14" fill="currentColor">
              <polygon points="6,1 1,7 6,13"/><polygon points="13,1 8,7 13,13"/>
            </svg>
          </button>
          <button className="pc-btn">
            <svg width="14" height="14" viewBox="0 0 14 14" fill="currentColor">
              <polygon points="2,1 12,7 2,13"/>
            </svg>
          </button>
          <div className="pc-progress">
            <div className="pc-fill" style={{ width: `${pct}%` }} />
            <div className="pc-dot"  style={{ left:  `${pct}%` }} />
          </div>
          <span className="pc-time">{time}</span>
          <span className="pc-quality">4K</span>
        </div>
      </div>
    </section>
  );
}
